import { BedrockAgentRuntimeClient, InvokeAgentCommand } from '@aws-sdk/client-bedrock-agent-runtime';
import { Vex } from 'vex-sdk';

const bedrock = new BedrockAgentRuntimeClient({ region: 'us-east-1' });
const vex = new Vex({ apiKey: 'your-vex-key' });

const sessionId = 'healthcare-session-456';
const command = new InvokeAgentCommand({
  agentId: 'your-agent-id',
  agentAliasId: 'your-alias',
  sessionId,
  inputText: 'Patient reports chest pain. Recommend next steps.'
});

const agentResponse = await bedrock.send(command);

// Verify with healthcare audit policy
const result = await vex.verify({
  input: agentResponse.completion,
  policy: 'fda-part11-audit',
  metadata: { sessionId, timestamp: new Date().toISOString() }
});

if (result.passed) {
  console.log('Auditable decision:', result.output);
} else {
  throw new Error(`Compliance violation: ${result.violations}`);
}

